import random
import time

def snake_game():
    """
    A simplified Snake game inspired by the Nokia 1997 version,
    playable in the console.
    """

    GRID_WIDTH = 20
    GRID_HEIGHT = 15
    SNAKE_CHAR = 'O'
    FOOD_CHAR = 'X'
    EMPTY_CHAR = ' '

    snake = [(GRID_WIDTH // 2, GRID_HEIGHT // 2)]  # Initial snake position (center)
    direction = (1, 0)  # Initial direction (right)
    food = generate_food(GRID_WIDTH, GRID_HEIGHT, snake)
    score = 0

    def generate_food(width, height, snake_body):
        """Generates food at a random location, avoiding the snake's body."""
        while True:
            x = random.randint(0, width - 1)
            y = random.randint(0, height - 1)
            if (x, y) not in snake_body:
                return (x, y)

    def display_grid(snake_body, food_pos):
        """Displays the game grid in the console."""
        grid = [[' ' for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        for x, y in snake_body:
            grid[y][x] = SNAKE_CHAR
        grid[food_pos[1]][food_pos[0]] = FOOD_CHAR

        for row in grid:
            print(''.join(row))
        print(f"Score: {score}")

    def get_direction():
        """Gets the player's input for direction."""
        # This is a simplified input method for console.
        # In a real game, you'd use proper input handling (e.g., curses).
        print("Enter direction (w/a/s/d, or q to quit): ", end="")
        move = input().lower()
        if move == 'w':
            return (0, -1)
        elif move == 's':
            return (0, 1)
        elif move == 'a':
            return (-1, 0)
        elif move == 'd':
            return (1, 0)
        elif move == 'q':
            return None  # Signal to quit
        else:
            return direction  # Invalid input, keep current direction

    while True:
        display_grid(snake, food)
        new_direction = get_direction()

        if new_direction is None:
            print("Game Over! You quit.")
            break

        direction = new_direction

        head_x, head_y = snake[0]
        new_head = (head_x + direction[0], head_y + direction[1])

        # Check for game over conditions
        if (
            new_head[0] < 0
            or new_head[0] >= GRID_WIDTH
            or new_head[1] < 0
            or new_head[1] >= GRID_HEIGHT
            or new_head in snake
        ):
            display_grid(snake, food)
            print("Game Over! Snake collided.")
            break

        snake.insert(0, new_head)  # Add new head

        if new_head == food:
            score += 1
            food = generate_food(GRID_WIDTH, GRID_HEIGHT, snake)
        else:
            snake.pop()  # Remove tail if no food eaten

        time.sleep(0.2)  # Adjust speed as needed

if __name__ == "__main__":
    print("Snake Game (Console Version)")
    snake_game()

